async function main() {
  console.log('Importing ' + DATA.length + ' products (skip if exists)...');
  // Load existing SKUs
  const existing = await prisma.product.findMany({ select: { sku: true, barcode: true } });
  const skus = new Set(existing.map(p => p.sku));
  const barcodes = new Set(existing.map(p => p.barcode).filter(Boolean));
  console.log('Existing products in DB:', skus.size);
  let created = 0, skipped = 0, errors = 0;
  for (const p of DATA) {
    if (skus.has(p.sku) || (p.barcode && barcodes.has(p.barcode))) { skipped++; continue; }
    const slug = p.slug + '-' + Date.now() % 100000;
    try {
      await prisma.product.create({ data: {
        sku: p.sku,
        barcode: p.barcode || undefined,
        name: p.name,
        slug,
        price: p.price || 0,
        costPrice: p.costPrice || undefined,
        stock: 0,
        packSize: p.packSize || undefined,
        packUnit: p.packSize ? 'unites' : undefined,
        categoryId: p.categoryId,
        status: 'ACTIVE',
        isVisible: true,
        tags: [],
        images: []
      }});
      skus.add(p.sku);
      if (p.barcode) barcodes.add(p.barcode);
      created++;
      if (created % 100 === 0) process.stdout.write(created + '...');
    } catch(e) {
      errors++;
      if (errors <= 5) console.log('ERR', p.sku, e.message.substring(0,60));
    }
  }
  console.log('Done - Created: ' + created + ' | Skipped: ' + skipped + ' | Errors: ' + errors);
  await prisma.$disconnect();
}
main().catch(async e => { console.error(e.message); await prisma.$disconnect(); process.exit(1); });
